      ((Control) boxContainer3).AddChild((Control) button2);
      ((Control) boxContainer3).AddChild((Control) button4);
      ((Control) boxContainer2).AddChild((Control) label);
      ((Control) boxContainer2).AddChild((Control) boxContainer3);
      ((Control) panelContainer2).AddChild((Control) boxContainer2);
      ((Control) this.RequestsContainer).AddChild((Control) panelContainer2);
    }
    ((Control) this.EmptyRequestsLabel).Visible = requests.Count == 0;
  }

